// Filter to include only the "Tasks" records and exclude "Comments" from the raw SF Task creation composite request.
var rawTaskRecords = flatten((vars.rawCompositeRequest.compositeRequest filter $.referenceId == "Tasks").body.records)

//Filter the response to include only "Tasks" and exclude "Comments" from the Salesforce Task creation composite response.
var taskResponse = vars.sfTaskUpdateResponse.compositeResponse filter $.referenceId == "Tasks"

// Append an index number to the Task creation composite response and filter out any failed records.
var indexedFailedRecords = ((flatten(taskResponse.body)) map ((item, index) -> item ++ {"number" :index }) ) filter $.success == false

//Function to consolidate composite requests and responses for constructing error record objects.
fun  ie(record,item) = {
		"attributes" : {"type" : "Integration_Error__c"},
        "Application__c": p('error.application'),
        "Client_Transaction_Reference_ID__c": uuid(),
        "Relevant_Object_Id__c": record.WorkOrderId,
        "Relevant_Object_Type__c": "SMB_Work_Order__c",
        "Error_Reason__c" : item.errors[0].statusCode,
        "Summary__c" : item.errors[0].statusCode,
        "Error_Message__c" : item.errors[0].message,
        "Severity__c": "ERROR",
        "Raw_Error_Message__c": write(record, 'application/json')
    	}
---
{
    "allOrNone" : false,
    "records" :  indexedFailedRecords map ((item, index) -> (ie(rawTaskRecords[item.number],item))  ) 

}

