// Separate input based on whether Opportunity_Line_Item__c exists
var withOLI = payload filter (item) -> item.Opportunity_Line_Item__c != null
//var withoutOLI = payload filter (item) -> item.Opportunity_Line_Item__c == null and item.Service_Occurance__c != null

// Group and process records with Opportunity_Line_Item__c
var groupedByOLI =
  withOLI groupBy ((item) -> item.Opportunity_Line_Item__c)
    mapObject ((value, key) -> {
      (key): value
    }) 
    pluck $
    map ((item) -> 
      (item[0] - "Service_Quantity__c" - "Service_Occurance__c") ++ {
        Opportunity_Line_Item__c: item[0].Opportunity_Line_Item__c,
        Service_Quantity__c: sizeOf(item) as String,
        Service_Occurance__c: (distinctBy(item.Service_Occurance__c, (v) -> v) joinBy ",")
      }
    )
/* 
// Group and process records without Opportunity_Line_Item__c
var groupedBySO =
  withoutOLI groupBy ((item) -> item.Service_Occurance__c as String)
    pluck ((items, key) ->
      (items[0] - "Service_Quantity__c" ) ++ {
        Service_Quantity__c: sizeOf(items) as String,
        Service_Occurance__c: key
      }
    )
*/

// Combine grouped records with disconnectedRecords
var baseSet = groupedByOLI ++ vars.disconnectedBssnRecords

// Filter records from matchingBssnWithQlids not in baseSet -- (to be marked "Disconnected")
var unmatchedBssnRecords =
    vars.matchingBssnWithQlids filter (record) ->
        isEmpty(
            baseSet filter (item) ->
                (item.Billing_System_External_Id__c default "") ==
                (record.Billing_System_External_Id__c default "")
)

---
baseSet ++ unmatchedBssnRecords

