/**
 * Pattern: Merge Objects
 * Category: Object Transformation
 * Difficulty: Intermediate
 *
 * Description: Merge two or more objects into one. Essential when combining data
 * from multiple API calls, enriching a record with lookup data, or assembling a
 * canonical model from different source systems. The ++ operator merges objects;
 * when keys collide, the right-hand object wins.
 *
 * Input (application/json):
 * {
 *   "customer": {
 *     "customerId": "C-100",
 *     "name": "Alice Chen",
 *     "email": "alice@example.com"
 *   },
 *   "billing": {
 *     "billingAddress": "123 Main St, San Francisco, CA 94102",
 *     "paymentMethod": "credit_card",
 *     "cardLast4": "4242"
 *   },
 *   "preferences": {
 *     "language": "en",
 *     "timezone": "America/Los_Angeles",
 *     "newsletter": true
 *   }
 * }
 *
 * Output (application/json):
 * {
 *   "customerId": "C-100",
 *   "name": "Alice Chen",
 *   "email": "alice@example.com",
 *   "billingAddress": "123 Main St, San Francisco, CA 94102",
 *   "paymentMethod": "credit_card",
 *   "cardLast4": "4242",
 *   "language": "en",
 *   "timezone": "America/Los_Angeles",
 *   "newsletter": true
 * }
 */
%dw 2.0
output application/json
---
payload.customer ++ payload.billing ++ payload.preferences

// Alternative 1 — merge with override (right wins on conflict):
// var defaults = {language: "en", timezone: "UTC", newsletter: false}
// var userPrefs = {timezone: "America/Los_Angeles", newsletter: true}
// ---
// defaults ++ userPrefs
// Output: {language: "en", timezone: "America/Los_Angeles", newsletter: true}

// Alternative 2 — conditional merge (add fields only if they exist):
// payload.customer ++
//     (if (payload.billing != null) payload.billing else {}) ++
//     (if (payload.preferences != null) payload.preferences else {})

// Alternative 3 — merge an array of objects into one:
// [payload.customer, payload.billing, payload.preferences]
//     reduce (item, acc = {}) -> acc ++ item

/**
 * Pattern: Nested Object Update
 * Category: Object Transformation
 * Difficulty: Advanced
 *
 * Description: Update a field deep inside a nested object without rebuilding the
 * entire structure. The update operator lets you target a specific path and
 * modify just that value — everything else stays intact. Critical for patching
 * API payloads, updating config structures, and modifying deeply nested
 * integration messages.
 *
 * Input (application/json):
 * {
 *   "orderId": "ORD-2026-1587",
 *   "customer": {
 *     "name": "Alice Chen",
 *     "address": {
 *       "street": "123 Main Street",
 *       "city": "San Francisco",
 *       "state": "CA",
 *       "zip": "94102",
 *       "country": "US"
 *     },
 *     "contacts": {
 *       "primary": {
 *         "email": "alice@oldcompany.com",
 *         "phone": "+1-555-0142"
 *       },
 *       "billing": {
 *         "email": "billing@oldcompany.com",
 *         "phone": "+1-555-0199"
 *       }
 *     }
 *   },
 *   "status": "processing"
 * }
 *
 * Output (application/json):
 * {
 *   "orderId": "ORD-2026-1587",
 *   "customer": {
 *     "name": "Alice Chen",
 *     "address": {
 *       "street": "456 Oak Avenue",
 *       "city": "San Francisco",
 *       "state": "CA",
 *       "zip": "94108",
 *       "country": "US"
 *     },
 *     "contacts": {
 *       "primary": {
 *         "email": "alice@newcompany.com",
 *         "phone": "+1-555-0142"
 *       },
 *       "billing": {
 *         "email": "billing@oldcompany.com",
 *         "phone": "+1-555-0199"
 *       }
 *     }
 *   },
 *   "status": "processing"
 * }
 */
%dw 2.0
output application/json
---
payload update {
    case address at .customer.address -> address ++ {
        street: "456 Oak Avenue",
        zip: "94108"
    }
    case email at .customer.contacts.primary.email -> "alice@newcompany.com"
}

// Alternative 1 — manual rebuild (verbose, but works in all DW versions):
// payload ++ {
//     customer: payload.customer ++ {
//         address: payload.customer.address ++ {
//             street: "456 Oak Avenue",
//             zip: "94108"
//         },
//         contacts: payload.customer.contacts ++ {
//             primary: payload.customer.contacts.primary ++ {
//                 email: "alice@newcompany.com"
//             }
//         }
//     }
// }

// Alternative 2 — update with transformation (e.g., uppercase a nested field):
// payload update {
//     case name at .customer.name -> upper(name)
// }

// Alternative 3 — update array elements within a nested structure:
// payload update {
//     case items at .order.lineItems -> items map (item) ->
//         if (item.sku == "SKU-100") item ++ {price: 139.99}
//         else item
