  (payload.sfOliResponse default [])
    map $.EnterpriseQuoteLineItemId__c
    filter ($ != null)
    distinctBy $

// 2) Matching sfBssn records - Keep if EQLI is not null AND exist in qliIds
var matchingBssnWithQlids =
  (payload.sfBssnResponse default [])
    filter (b) ->
      (
        b.EnterpriseQuoteLineItemId__c != null
        and (qliIds contains b.EnterpriseQuoteLineItemId__c)
      )

// 3) Filter out duplicate records by Billing_System_External_Id__c
var uniqueSfBssnRecords =
    (matchingBssnWithQlids default [] )
        distinctBy ((item) -> item.Billing_System_External_Id__c)

---
// 4) Build update payload with disconnected status
uniqueSfBssnRecords default [] map {
	"As_of__c": now(),
	"Service_Status__c " : "Disconnected",
	"Billing_System_External_Id__c": $.Billing_System_External_Id__c
}

