import sum from dw::core::Arrays

fun toNum(v) = (v as Number) default 0

fun parts(v) =
((v default "") as String splitBy ",")
map ((s) -> trim(s))
filter ((s) -> s != "")

fun totalQty(q) =
if (((q default "") as String) contains ",")
sum(parts(q) map ((x) -> toNum(x)))
else
toNum(q)

// Normalize input into an Array safely
fun asArray(p) = do {
var s = if (p is String) trim(p) else null
var normalized =
if (p == null) []
else if (p is Array) p
else if (p is Object) [p]
else if (p is String and (s == "" or s == "null")) []
else if (p is String) read(p, "application/json")
else p
---
(normalized default []) as Array
}

---
asArray(payload) flatMap ((item) -> do {
var occs = parts(item.Service_Occurance__c)
var qtyTotal = totalQty(item.Service_Quantity__c)

var base =
(item - "Service_Quantity__c" - "Service_Occurance__c" - "Service_Rate__c") ++ {
Service_Rate__c: toNum(item.Service_Rate__c)
}

---
if (isEmpty(occs))
[]
else if (sizeOf(occs) > 1)
// multiple occurrences -> one record per occurrence, qty forced to "1"
occs map ((o) ->
base ++ {
Service_Quantity__c: "1",
Service_Occurance__c: o
}
)
else
// single occurrence -> explode total qty into records with qty "1"
(1 to (qtyTotal as Number)) map ((i) ->
base ++ {
Service_Quantity__c: "1",
Service_Occurance__c: occs[0]
}
)
})

