var data  = vars.sfBssnOnlyRecords default []

// One record per Billing_System_External_Id__c (same as your original logic)
var uniqueSfBssnRecords = 
    data distinctBy ((item) -> item.Billing_System_External_Id__c)

---

// Build update payload with aggregated values + disconnected status
uniqueSfBssnRecords default [] map (u) -> {
    As_of__c: now(),
    Service_Status__c:  "Disconnected",
    Billing_System_External_Id__c: u.Billing_System_External_Id__c,

    // Concatenate occurrences for this external id: e.g. "11,12"
    //Build a comma-separated list of unique Service Occurrence values, ignoring duplicates.
    Service_Occurance__c:
        (data
            filter (r) -> r.Billing_System_External_Id__c == u.Billing_System_External_Id__c
        )
        reduce ((r, acc = "") ->
            if (acc == "") 
                r.Service_Occurance__c
            else if ((acc splitBy ",") contains r.Service_Occurance__c)
                acc
            else
                acc ++ "," ++ r.Service_Occurance__c
        ),

    // Number of records for this external id
    Service_Quantity__c:
        sizeOf(data
            filter (r) -> r.Billing_System_External_Id__c == u.Billing_System_External_Id__c
        ) as String

    // Sum of original Service_Quantity__c for this external id
   /* Actual_Service_Quantity__c:
        (data
            filter (r) -> r.Billing_System_External_Id__c == u.Billing_System_External_Id__c
        )
        reduce ((r, acc = 0) -> acc + (r.Service_Quantity__c  default 0)) */

